import { useEffect, useState, useCallback } from "react";
import "./CompanyDashboard.scss";

export default function CompanyDashboard() {
  const [bugs, setBugs] = useState([]);
  const [filter, setFilter] = useState("all");
  const [showModal, setShowModal] = useState(false);
  const [selectedBug, setSelectedBug] = useState(null);
  const [severity, setSeverity] = useState("low");
  const [reward, setReward] = useState("");

  const token = localStorage.getItem("token");

  const fetchCompanyBugs = useCallback(() => {
    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then((res) => res.json())
      .then((data) => {
        if (Array.isArray(data)) setBugs(data);
        else if (Array.isArray(data.bugs)) setBugs(data.bugs);
        else setBugs([]);
      });
  }, [token]);

  useEffect(() => {
    const role = localStorage.getItem("role");

    if (!token) return (window.location.href = "/");
    if (role !== "company" && role !== "admin")
      return (window.location.href = "/hacker");

    fetchCompanyBugs();
  }, [fetchCompanyBugs, token]);

  const filteredBugs =
    filter === "all" ? bugs : bugs.filter((b) => b.status === filter);

  const openApprove = (bug) => {
    setSelectedBug(bug);
    setSeverity("low");
    setReward("");
    setShowModal(true);
  };

  const approveBug = async () => {
    if (!reward || reward <= 0) return;

    await fetch(`http://localhost:5000/api/bugs/validate/${selectedBug._id}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        status: "approved",
        severity,
        reward: Number(reward),
      }),
    });

    setShowModal(false);
    fetchCompanyBugs();
  };

  const rejectBug = async (id) => {
    await fetch(`http://localhost:5000/api/bugs/validate/${id}`, {
      method: "PATCH",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ status: "rejected" }),
    });

    fetchCompanyBugs();
  };

  return (
    <div className="company-dashboard">
      {/* HEADER */}
      <header className="company-header">
        <h1>🏢 Company Dashboard</h1>
        <button
          className="logout-btn"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </header>

      {/* FILTER BAR */}
      <div className="filter-bar">
        {["all", "submitted", "approved", "rejected"].map((f) => (
          <button
            key={f}
            className={filter === f ? "active" : ""}
            onClick={() => setFilter(f)}
          >
            {f.toUpperCase()}
          </button>
        ))}
      </div>

      {/* BUG CARDS */}
      <div className="bug-list">
        {filteredBugs.length === 0 ? (
          <p className="muted">No bugs found.</p>
        ) : (
          filteredBugs.map((bug) => (
            <div className="bug-card" key={bug._id}>
              <div className="bug-top">
                <h3>{bug.title}</h3>
                <span className={`status ${bug.status}`}>{bug.status}</span>
              </div>

              <p className="bug-desc">{bug.description}</p>

              <div className="bug-meta">
                <span className={`severity ${bug.severity}`}>
                  {bug.severity}
                </span>
                <span className="email">
                  🧑‍💻 {bug.submittedBy?.email}
                </span>
              </div>

              {bug.status === "submitted" && (
                <div className="bug-actions">
                  <button
                    className="approve"
                    onClick={() => openApprove(bug)}
                  >
                    Approve
                  </button>
                  <button
                    className="reject"
                    onClick={() => rejectBug(bug._id)}
                  >
                    Reject
                  </button>
                </div>
              )}
            </div>
          ))
        )}
      </div>

      {/* APPROVE MODAL */}
      {showModal && (
        <div className="modal-backdrop">
          <div className="modal-box">
            <h2>Approve Bug</h2>

            <label>Severity</label>
            <select
              value={severity}
              onChange={(e) => setSeverity(e.target.value)}
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
              <option value="critical">Critical</option>
            </select>

            <label>Reward (₹)</label>
            <input
              type="number"
              value={reward}
              onChange={(e) => setReward(e.target.value)}
            />

            <div className="modal-actions">
              <button className="approve" onClick={approveBug}>
                Confirm
              </button>
              <button
                className="reject"
                onClick={() => setShowModal(false)}
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
